import { describe, expect, it } from "vitest";
import { priceOrder } from "../src/pricing.js";

// Tests for priceOrder, exercising the behavior documented in src/pricing.js.
//
// Contract recap:
//   subtotalCents = sum of unitCents * qty over all lines ([] -> all zeros)
//   tier discount = 10% of subtotal (rounded, .5 up) when subtotal >= 10000
//   coupon discount = capped pct (max 30) of the POST-tier subtotal (rounded, .5 up)
//   discountCents = tier + coupon
//   totalCents = subtotalCents - discountCents
//   qty must be a positive integer, else RangeError.

describe("priceOrder", () => {
  describe("return shape", () => {
    it("returns exactly the three documented integer fields", () => {
      const result = priceOrder([{ unitCents: 500, qty: 2 }]);
      expect(Object.keys(result).sort()).toEqual([
        "discountCents",
        "subtotalCents",
        "totalCents",
      ]);
      expect(Number.isInteger(result.subtotalCents)).toBe(true);
      expect(Number.isInteger(result.discountCents)).toBe(true);
      expect(Number.isInteger(result.totalCents)).toBe(true);
    });

    it("always satisfies total = subtotal - discount", () => {
      const cases = [
        priceOrder([]),
        priceOrder([{ unitCents: 500, qty: 3 }]),
        priceOrder([{ unitCents: 10000, qty: 1 }]),
        priceOrder([{ unitCents: 2000, qty: 1 }], { pct: 10 }),
        priceOrder([{ unitCents: 20000, qty: 1 }], { pct: 50 }),
      ];
      for (const r of cases) {
        expect(r.totalCents).toBe(r.subtotalCents - r.discountCents);
      }
    });
  });

  describe("subtotal", () => {
    it("returns all zeros for an empty order", () => {
      expect(priceOrder([])).toEqual({
        subtotalCents: 0,
        discountCents: 0,
        totalCents: 0,
      });
    });

    it("computes unitCents * qty for a single line", () => {
      expect(priceOrder([{ unitCents: 500, qty: 3 }])).toEqual({
        subtotalCents: 1500,
        discountCents: 0,
        totalCents: 1500,
      });
    });

    it("sums unitCents * qty across multiple lines", () => {
      const lines = [
        { unitCents: 100, qty: 2 }, // 200
        { unitCents: 250, qty: 3 }, // 750
        { unitCents: 50, qty: 1 }, //   50
      ];
      expect(priceOrder(lines)).toEqual({
        subtotalCents: 1000,
        discountCents: 0,
        totalCents: 1000,
      });
    });
  });

  describe("tier discount", () => {
    it("does not apply just below the 10000 threshold", () => {
      const r = priceOrder([{ unitCents: 9999, qty: 1 }]);
      expect(r.discountCents).toBe(0);
      expect(r.totalCents).toBe(9999);
    });

    it("applies exactly at the 10000 threshold (10% of subtotal)", () => {
      expect(priceOrder([{ unitCents: 10000, qty: 1 }])).toEqual({
        subtotalCents: 10000,
        discountCents: 1000,
        totalCents: 9000,
      });
    });

    it("applies when the threshold is reached via summed lines", () => {
      const lines = [
        { unitCents: 4000, qty: 2 }, // 8000
        { unitCents: 2000, qty: 1 }, // 2000  -> 10000 total
      ];
      expect(priceOrder(lines)).toEqual({
        subtotalCents: 10000,
        discountCents: 1000,
        totalCents: 9000,
      });
    });

    it("does not apply when summed lines fall just short", () => {
      const lines = [{ unitCents: 3000, qty: 3 }]; // 9000
      expect(priceOrder(lines)).toEqual({
        subtotalCents: 9000,
        discountCents: 0,
        totalCents: 9000,
      });
    });

    it("rounds the tier discount to the nearest cent with .5 going up", () => {
      // 10005 * 0.10 = 1000.5 -> 1001
      expect(priceOrder([{ unitCents: 10005, qty: 1 }])).toEqual({
        subtotalCents: 10005,
        discountCents: 1001,
        totalCents: 9004,
      });
    });

    it("rounds a tier fraction below .5 down", () => {
      // 10004 * 0.10 = 1000.4 -> 1000
      expect(priceOrder([{ unitCents: 10004, qty: 1 }])).toEqual({
        subtotalCents: 10004,
        discountCents: 1000,
        totalCents: 9004,
      });
    });
  });

  describe("coupon discount", () => {
    it("is ignored when no coupon is supplied", () => {
      expect(priceOrder([{ unitCents: 2000, qty: 1 }])).toEqual({
        subtotalCents: 2000,
        discountCents: 0,
        totalCents: 2000,
      });
    });

    it("applies a straightforward percentage below the tier threshold", () => {
      // 2000 * 10% = 200
      expect(priceOrder([{ unitCents: 2000, qty: 1 }], { pct: 10 })).toEqual({
        subtotalCents: 2000,
        discountCents: 200,
        totalCents: 1800,
      });
    });

    it("treats pct 0 as no coupon discount", () => {
      expect(priceOrder([{ unitCents: 2000, qty: 1 }], { pct: 0 })).toEqual({
        subtotalCents: 2000,
        discountCents: 0,
        totalCents: 2000,
      });
    });

    it("rounds the coupon discount to the nearest cent with .5 going up", () => {
      // 10 * 15% = 1.5 -> 2
      expect(priceOrder([{ unitCents: 10, qty: 1 }], { pct: 15 })).toEqual({
        subtotalCents: 10,
        discountCents: 2,
        totalCents: 8,
      });
    });

    it("rounds a coupon fraction below .5 down", () => {
      // 30 * 15% = 4.5 would be .5; use 20 * 15% = 3.0, and 14*15%=2.1 -> 2
      expect(priceOrder([{ unitCents: 14, qty: 1 }], { pct: 15 })).toEqual({
        subtotalCents: 14,
        discountCents: 2,
        totalCents: 12,
      });
    });

    it("applies pct exactly 30 without capping", () => {
      // 1000 * 30% = 300
      expect(priceOrder([{ unitCents: 1000, qty: 1 }], { pct: 30 })).toEqual({
        subtotalCents: 1000,
        discountCents: 300,
        totalCents: 700,
      });
    });

    it("caps pct just above 30 back down to 30", () => {
      // pct 31 -> 30; 1000 * 30% = 300 (same as pct 30)
      expect(priceOrder([{ unitCents: 1000, qty: 1 }], { pct: 31 })).toEqual({
        subtotalCents: 1000,
        discountCents: 300,
        totalCents: 700,
      });
    });

    it("caps large pct values (50, 100) at 30", () => {
      const at50 = priceOrder([{ unitCents: 1000, qty: 1 }], { pct: 50 });
      const at100 = priceOrder([{ unitCents: 1000, qty: 1 }], { pct: 100 });
      const at30 = priceOrder([{ unitCents: 1000, qty: 1 }], { pct: 30 });
      expect(at50).toEqual(at30);
      expect(at100).toEqual(at30);
      expect(at50.discountCents).toBe(300);
    });
  });

  describe("tier and coupon combined", () => {
    it("applies the coupon to the POST-tier subtotal, not the raw subtotal", () => {
      // subtotal 10000, tier 1000, post-tier base 9000, coupon 10% of 9000 = 900.
      // (If the coupon used the raw subtotal it would be 1000, not 900.)
      expect(priceOrder([{ unitCents: 10000, qty: 1 }], { pct: 10 })).toEqual({
        subtotalCents: 10000,
        discountCents: 1900,
        totalCents: 8100,
      });
    });

    it("combines tier and a capped coupon", () => {
      // subtotal 20000, tier 2000, post-tier 18000, coupon capped to 30% = 5400.
      expect(priceOrder([{ unitCents: 20000, qty: 1 }], { pct: 50 })).toEqual({
        subtotalCents: 20000,
        discountCents: 7400,
        totalCents: 12600,
      });
    });

    it("combines tier and coupon with a non-round percentage", () => {
      // subtotal 15000, tier round(1500)=1500, post-tier 13500,
      // coupon 12% of 13500 = 1620.
      expect(priceOrder([{ unitCents: 15000, qty: 1 }], { pct: 12 })).toEqual({
        subtotalCents: 15000,
        discountCents: 3120,
        totalCents: 11880,
      });
    });
  });

  describe("qty validation", () => {
    it("throws RangeError for qty of 0", () => {
      expect(() => priceOrder([{ unitCents: 100, qty: 0 }])).toThrow(RangeError);
    });

    it("throws RangeError for a negative qty", () => {
      expect(() => priceOrder([{ unitCents: 100, qty: -1 }])).toThrow(
        RangeError,
      );
    });

    it("throws RangeError for a non-integer qty", () => {
      expect(() => priceOrder([{ unitCents: 100, qty: 1.5 }])).toThrow(
        RangeError,
      );
    });

    it("throws RangeError for a NaN qty", () => {
      expect(() => priceOrder([{ unitCents: 100, qty: NaN }])).toThrow(
        RangeError,
      );
    });

    it("throws when any line in an otherwise valid order is invalid", () => {
      const lines = [
        { unitCents: 100, qty: 2 },
        { unitCents: 200, qty: 0 }, // invalid
        { unitCents: 300, qty: 1 },
      ];
      expect(() => priceOrder(lines)).toThrow(RangeError);
    });

    it("accepts a qty of 1 as the smallest valid positive integer", () => {
      expect(priceOrder([{ unitCents: 100, qty: 1 }])).toEqual({
        subtotalCents: 100,
        discountCents: 0,
        totalCents: 100,
      });
    });
  });
});

